/*
  Rebuilt file-open safe globe script.
  Generated: 20260609_155741

  This version:
  - works under file://
  - embeds the earth texture as data URI
  - does NOT append ?v= to the data URI
  - draws a fallback sphere if the texture fails
*/

(function () {
  "use strict";

  function log() {
    try {
      console.log.apply(console, ["[FileOpen Globe]"].concat([].slice.call(arguments)));
    } catch (e) {}
  }

  var stage = document.getElementById("three-hero-stage");

  if (!stage) {
    console.error("[FileOpen Globe] #three-hero-stage not found.");
    return;
  }

  if (!window.THREE) {
    console.error("[FileOpen Globe] THREE not found. Make sure vendor/three.min.js is loaded first.");
    stage.innerHTML =
      '<div style="position:absolute;left:50%;top:50%;transform:translate(-50%,-50%);' +
      'color:white;font:700 14px Arial;background:rgba(30,80,140,.35);' +
      'padding:10px 14px;border-radius:999px;">THREE.js not loaded</div>';
    return;
  }

  var scene = new THREE.Scene();

  var renderer = new THREE.WebGLRenderer({
    antialias: true,
    alpha: true,
    powerPreference: "high-performance"
  });

  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 1.8));
  renderer.setClearColor(0xF5F8FC, 1);

  if (THREE.sRGBEncoding && renderer.outputEncoding !== undefined) {
    renderer.outputEncoding = THREE.sRGBEncoding;
  }

  stage.innerHTML = "";
  stage.appendChild(renderer.domElement);

  var camera = new THREE.PerspectiveCamera(38, 1, 0.1, 1000);

  var GLOBE_RADIUS = 17.6;
  var GLOBE_Y = -23.2;
  var CAMERA_Z = 27.2;
  var LOOK_AT_Y = -9.8;
  var ROT_X = 0.08;
  var ROT_Y = -2.10;
  var ROT_SPEED = 0.00025;

  camera.position.set(0, 0.0, CAMERA_Z);
  camera.lookAt(0, LOOK_AT_Y, 0);

  scene.add(new THREE.AmbientLight(0xffffff, 1.12));

  var keyLight = new THREE.DirectionalLight(0xffffff, 0.52);
  keyLight.position.set(6, 5, 8);
  scene.add(keyLight);

  var fillLight = new THREE.DirectionalLight(0xddefff, 0.38);
  fillLight.position.set(-8, 2, 8);
  scene.add(fillLight);

  var globe = null;
  var rim = null;

  function createGlobe(texture) {
    var globeGeometry = new THREE.SphereGeometry(GLOBE_RADIUS, 192, 192);

    var globeMaterial;

    if (texture) {
      if (THREE.sRGBEncoding && texture.encoding !== undefined) {
        texture.encoding = THREE.sRGBEncoding;
      }

      texture.anisotropy = renderer.capabilities.getMaxAnisotropy
        ? Math.min(8, renderer.capabilities.getMaxAnisotropy())
        : 1;

      texture.wrapS = THREE.RepeatWrapping;
      texture.wrapT = THREE.ClampToEdgeWrapping;

      globeMaterial = new THREE.MeshPhongMaterial({
        map: texture,
        shininess: 2,
        specular: new THREE.Color(0x18324a)
      });
    } else {
      globeMaterial = new THREE.MeshPhongMaterial({
        color: 0x6ea7d8,
        emissive: 0x16304a,
        shininess: 2,
        specular: new THREE.Color(0x18324a)
      });
    }

    globe = new THREE.Mesh(globeGeometry, globeMaterial);
    globe.position.set(0, GLOBE_Y, 0);
    globe.rotation.set(ROT_X, ROT_Y, 0);
    scene.add(globe);

    var rimGeometry = new THREE.SphereGeometry(GLOBE_RADIUS * 1.012, 128, 128);
    var rimMaterial = new THREE.MeshBasicMaterial({
      color: 0xd7ecff,
      transparent: true,
      opacity: 0.07,
      side: THREE.BackSide,
      depthWrite: false
    });

    rim = new THREE.Mesh(rimGeometry, rimMaterial);
    rim.position.copy(globe.position);
    rim.rotation.copy(globe.rotation);
    scene.add(rim);

    log("globe created", texture ? "with texture" : "fallback material");
  }

  function animate() {
    requestAnimationFrame(animate);

    if (globe) globe.rotation.y += ROT_SPEED;
    if (rim) rim.rotation.y += ROT_SPEED;

    renderer.render(scene, camera);
  }

  function resize() {
    var w = stage.clientWidth || window.innerWidth || 1200;
    var h = stage.clientHeight || window.innerHeight || 800;

    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
  }

  window.addEventListener("resize", resize);
  resize();

  var img = new Image();

  img.onload = function () {
    try {
      var texture = new THREE.Texture(img);
      texture.needsUpdate = true;
      createGlobe(texture);
      animate();
      log("texture loaded from embedded data URI");
    } catch (e) {
      console.error("[FileOpen Globe] texture creation failed:", e);
      createGlobe(null);
      animate();
    }
  };

  img.onerror = function (err) {
    console.error("[FileOpen Globe] embedded image failed:", err);
    createGlobe(null);
    animate();
  };

  /*
    Important:
    No ?v= after this data URI.
  */
  img.src = "data:image/jpeg;base64,";

  log("script started");
})();
